import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

import {
  AppBar,
  Toolbar,
  Typography,
  Box,
  Button,
  Container,
  Paper,
  TextField,
  MenuItem,
} from "@mui/material";

import "./CreatePage.css";

function CreatePage() {
  const navigate = useNavigate();

  const [title, setTitle] = useState("");

  const [location, setLocation] = useState("");

  const [date, setDate] = useState("");

  const [category, setCategory] = useState("");

  const [storage, setStorage] = useState("");

  const [description, setDescription] = useState("");

useEffect(() => {

  const verifyUser = async () => {

    const token = localStorage.getItem("token");

    if (!token) {

      navigate("/");

      return;
    }

    try {

      const response = await fetch(
        "http://127.0.0.1:5000/profile",
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      if (!response.ok) {

        localStorage.removeItem("token");

        navigate("/");
      }

    } catch (error) {

      navigate("/");
    }
  };

  verifyUser();

}, []);
  
  return (
    <>
      {/* ✅ CreatePage 전용 Navbar */}
      <AppBar position="static" className="create-navbar">
        <Toolbar className="create-navbar-toolbar">

          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />

        </Toolbar>
      </AppBar>

      {/* 배너 */}
      <Box className="create-header">
        <Typography variant="h4" className="create-title">
          유실물 등록
        </Typography>

        <Typography className="create-subtitle">
          유실물 정보를 입력해주세요
        </Typography>
      </Box>

      {/* 폼 */}
      <Container maxWidth="md">
        <Paper className="create-paper">

          <Button
            variant="contained"
            component="label"
            className="upload-button"
          >
            이미지 업로드
            <input hidden type="file" />
          </Button>

          <TextField fullWidth label="습득 장소" margin="normal" />

          <TextField
            fullWidth
            label="습득 일자"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            placeholder="0000-00-00"
          />

          <TextField
            fullWidth
            select
            label="물품 분류"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            margin="normal"
          >
            <MenuItem value="노트북">노트북</MenuItem>
            <MenuItem value="태블릿">태블릿</MenuItem>
            <MenuItem value="휴대폰">휴대폰</MenuItem>
            <MenuItem value="지갑">지갑</MenuItem>
            <MenuItem value="가방">가방</MenuItem>
            <MenuItem value="기타">기타</MenuItem>
          </TextField>

          {category === "기타" && (
            <TextField fullWidth label="직접 입력" margin="normal" />
          )}

          <TextField
            fullWidth
            select
            label="보관 장소"
            margin="normal"
          >
            <MenuItem value="화도관">화도관 경비실</MenuItem>
            <MenuItem value="비마관">비마관 경비실</MenuItem>
            <MenuItem value="새빛관">새빛관 경비실</MenuItem>
            <MenuItem value="참빛관">참빛관 경비실</MenuItem>
            <MenuItem value="복지관">복지관 경비실</MenuItem>
            <MenuItem value="한울관">한울관 경비실</MenuItem>
            <MenuItem value="연구관">연구관 경비실</MenuItem>
          </TextField>

          <TextField
            fullWidth
            multiline
            rows={5}
            label="상세 정보"
            margin="normal"
          />

          <Button fullWidth variant="contained" className="submit-button">
            게시물 등록
          </Button>

        </Paper>
      </Container>
    </>
  );
}

export default CreatePage;
